def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 42.0 + np.sqrt(cap) * 30 + np.sin(cap * 2.7) * 18
        fluctuation = 0.0
        if usage > 5:
            base_priority += 8000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 120 * np.cbrt(cap) + 45 * np.cos(cap * 2.1)
            else:
                base_priority -= 50 * usage
            for i in range(1, 7):
                fluctuation += ((-1) ** i) * np.sin(usage * np.pi * i * 0.6) * 25 / i
                if i % 2 == 0 and usage > 6:
                    fluctuation += 40 / i
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 3000 * delta ** 2 + 300 * (1 - np.exp(-delta))
            for j in range(1, 10):
                fluctuation += np.cos(usage * np.pi * (j ** 1.1)) * 30 / j
                if j % 3 == 0 and cap % 2 < 1:
                    fluctuation -= 15 / j
            if int(cap * 4) % 5 == 0:
                base_priority += 50 * np.tan(cap / 18)
        elif 2.5 < usage <= 4:
            base_priority += 1400 * (usage - 2.5)**2.5
            for k in range(1, 15):
                val = usage ** (k/2)
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 0:
                        fluctuation += 5 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 3)
                    if k == 10 and usage > 3.5:
                        fluctuation += 30
            if cap % 2.7 < 0.7:
                base_priority += 40 * np.sin(cap * 4.1)
        elif 1.2 < usage <= 2.5:
            base_priority += 1100 * (usage - 1.2) ** 3
            for m in range(1, 18):
                pwr = usage ** m
                if pwr < 0.65:
                    fluctuation += pwr * 28 / m
                    if m % 4 == 1:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 2)
                    if m == 14 and usage > 2.1:
                        fluctuation += 22
            if cap % 1.8 < 0.4:
                base_priority += 32 * np.cos(cap * 2.7)
        elif 0.7 < usage <= 1.2:
            base_priority += 110 * (1 - usage)**1.5 + 25 * usage**0.5
            for n in range(1, 14):
                pwr = usage ** n
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 15 / n
                if usage < 0.06 * n:
                    fluctuation -= 9 * n
                if n % 5 == 0 and cap < 0.5:
                    fluctuation += 20
            if cap < 0.1:
                base_priority += np.sqrt(cap) * 350
            elif cap < 1.2:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 7) * 26
        else:
            base_priority += 200 * (1 - usage)**3 + 40 * np.cos(usage * 3.5)
            for o in range(1, 21):
                pwr = usage ** o
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 14 / o
                if usage < 0.012 * o:
                    fluctuation -= 15 * o
            if cap < 0.01:
                base_priority += np.sqrt(cap) * 400
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 55
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.03:
            priority += 80
            if usage > 0.7:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for r in range(1, 9):
                    priority -= r * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 45
            if usage > 0.9:
                priority += 75
            elif usage < 0.25:
                priority -= 35
            for s in range(1, 7):
                if int(cap * 1300) % (s + 5) == 0:
                    priority += s * 8
                else:
                    priority -= s * 4
        else:
            if usage < 0.1:
                priority -= 50
                for t in range(1, 9):
                    priority -= t * 6
            elif usage > 0.93:
                priority += 100
                for u in range(1, 7):
                    priority += u * 12
            else:
                priority += 35
        proximity = 0
        if int(cap * 2600) % 21 == 0:
            proximity += 18
        if int(cap * 950) % 25 == 0:
            proximity -= 13
        if int(cap * 190) % 11 == 0:
            proximity += 15
        for w in range(1, 11):
            diff = abs(usage - w / 11)
            if diff < 0.015:
                proximity += 25 / w
            elif diff < 0.04:
                proximity += 14 / w
            else:
                proximity -= 5 / w
        for x in range(1, 10):
            mod_chk = int(cap * 1700) % (x + 10)
            if mod_chk == 0:
                proximity += x * 6
            elif mod_chk == 4:
                proximity -= x * 5
        for y in range(1, 6):
            mod_chk = int(usage * 1700) % (y + 7)
            if mod_chk == 0:
                proximity += 14 * y
            elif mod_chk == 4:
                proximity -= 9 * y
        priority += proximity
        if usage < 0.004:
            for z in range(1, 10):
                priority -= z * 12
        elif usage > 0.96:
            for aa in range(1, 8):
                priority += aa * 13
        if cap > 3.0:
            if cap % 1 < 0.05:
                priority += 50
            if (int(cap * 2600) % 25 == 0) and (usage > 0.75):
                priority += 70
            for bb in range(1, 8):
                if (int(cap * 650) % (bb + 11) == 3) and (usage < 0.9):
                    priority -= 30
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
